(function () {
  function addStyle(){ if(document.getElementById('huf-style'))return; var s=document.createElement('style'); s.id='huf-style'; s.textContent='.huf-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.huf-actions{display:flex;gap:8px;flex-wrap:wrap;align-items:end}.huf-actions input{min-width:220px}.huf-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:10px;margin-top:12px}.huf-card{background:#f8fafc;border:1px solid #e5e7eb;border-radius:10px;padding:10px}.huf-table{width:100%;border-collapse:collapse}.huf-table td,.huf-table th{border:1px solid #e5e7eb;padding:5px;text-align:center}.huf-step{padding:6px;border-bottom:1px solid #e5e7eb}.huf-code{word-break:break-all;padding:10px;border-radius:8px;background:#e8f4fd;border-left:4px solid #007bff}'; document.head.appendChild(s); }
  function mount(host){ if(!host||host.dataset.hufMounted)return; host.dataset.hufMounted='1'; addStyle(); host.innerHTML='<div class="huf-wrap"><h4>🗜️ Mã hóa Huffman</h4><div class="huf-actions"><label>Văn bản<input data-text value="abracadabra"></label><button type="button" data-build>Xây dựng cây Huffman</button></div><div class="huf-grid"><div class="huf-card"><strong>Bảng tần suất</strong><div data-freq></div></div><div class="huf-card"><strong>Các bước hàng đợi ưu tiên</strong><div data-steps></div></div><div class="huf-card"><strong>Bảng mã</strong><div data-codes></div></div></div><div class="huf-card"><strong>Cây Huffman</strong><pre data-tree></pre></div><div class="huf-code"></div></div>'; function build(){var text=host.querySelector('[data-text]').value||'abracadabra',freq={}; text.split('').forEach(function(c){freq[c]=(freq[c]||0)+1;}); var q=Object.keys(freq).map(function(c){return {ch:c,w:freq[c]};}), steps=[]; q.sort(function(a,b){return a.w-b.w;}); while(q.length>1){var a=q.shift(),b=q.shift(),n={ch:null,w:a.w+b.w,l:a,r:b}; steps.push('Ghép '+label(a)+' và '+label(b)+' → '+n.w); q.push(n); q.sort(function(a,b){return a.w-b.w;});} var root=q[0], codes={}; function label(n){return (n.ch===null?'node':n.ch)+':'+n.w;} function walk(n,p){if(n.ch!==null){codes[n.ch]=p||'0';return;} walk(n.l,p+'0'); walk(n.r,p+'1');} function lines(n,prefix){if(!n)return []; var here=prefix+(n.ch===null?'•':n.ch)+'('+n.w+')'; return [here].concat(lines(n.l,prefix+' 0→ '),lines(n.r,prefix+' 1→ '));} walk(root,''); var enc=text.split('').map(function(c){return codes[c];}).join(''), fixed=text.length*Math.ceil(Math.log2(Object.keys(freq).length||1)), ratio=fixed?100*(1-enc.length/fixed):0; host.querySelector('[data-freq]').innerHTML='<table class="huf-table"><tr><th>Ký tự</th><th>Tần suất</th></tr>'+Object.keys(freq).map(function(c){return '<tr><td>'+c+'</td><td>'+freq[c]+'</td></tr>';}).join('')+'</table>'; host.querySelector('[data-steps]').innerHTML=steps.map(function(s){return '<div class="huf-step">'+s+'</div>';}).join(''); host.querySelector('[data-codes]').innerHTML='<table class="huf-table"><tr><th>Ký tự</th><th>Mã</th></tr>'+Object.keys(codes).sort().map(function(c){return '<tr><td>'+c+'</td><td>'+codes[c]+'</td></tr>';}).join('')+'</table>'; host.querySelector('[data-tree]').textContent=lines(root,'').join('\n'); host.querySelector('.huf-code').innerHTML='Chuỗi mã hóa: <strong>'+enc+'</strong><br>Số bit Huffman: '+enc.length+'. Mã cố định xấp xỉ: '+fixed+' bit. Tỉ lệ nén: <strong>'+ratio.toFixed(1)+'%</strong>.';} host.querySelector('[data-build]').onclick=build; build(); }
  document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('[data-demo="huffman-coding"]').forEach(mount);});
}());
